CREATE TABLE "Affiliation" (
  "affiliation_id" number PRIMARY KEY,
  "name" text,
  "address" text
);

CREATE TABLE "Author" (
  "author_id" number PRIMARY KEY,
  "name" text,
  "email" text
);

CREATE TABLE "Author_list" (
  "paper_id" text PRIMARY KEY,
  "author_id" number,
  "affiliation_id" number,
  FOREIGN KEY ("affiliation_id") REFERENCES "Affiliation"("affiliation_id"),
  FOREIGN KEY ("author_id") REFERENCES "Author"("author_id"),
  FOREIGN KEY ("paper_id") REFERENCES "Paper"("paper_id")
);

CREATE TABLE "Citation" (
  "paper_id" text PRIMARY KEY,
  "cited_paper_id" text,
  FOREIGN KEY ("cited_paper_id") REFERENCES "Paper"("paper_id"),
  FOREIGN KEY ("paper_id") REFERENCES "Paper"("paper_id")
);

CREATE TABLE "Paper" (
  "paper_id" text PRIMARY KEY,
  "title" text,
  "venue" text,
  "year" number
);

CREATE TABLE "author" (
  "aid" number PRIMARY KEY,
  "homepage" text,
  "name" text,
  "oid" number
);

CREATE TABLE "conference" (
  "cid" number PRIMARY KEY,
  "homepage" text,
  "name" text
);

CREATE TABLE "domain" (
  "did" number PRIMARY KEY,
  "name" text
);

CREATE TABLE "domain_author" (
  "aid" number,
  "did" number PRIMARY KEY,
  FOREIGN KEY ("did") REFERENCES "domain"("did"),
  FOREIGN KEY ("aid") REFERENCES "author"("aid")
);

CREATE TABLE "domain_conference" (
  "cid" number,
  "did" number PRIMARY KEY,
  FOREIGN KEY ("did") REFERENCES "domain"("did"),
  FOREIGN KEY ("cid") REFERENCES "conference"("cid")
);

CREATE TABLE "journal" (
  "homepage" text,
  "jid" number PRIMARY KEY,
  "name" text
);

CREATE TABLE "domain_journal" (
  "did" number PRIMARY KEY,
  "jid" number,
  FOREIGN KEY ("did") REFERENCES "domain"("did"),
  FOREIGN KEY ("jid") REFERENCES "journal"("jid")
);

CREATE TABLE "keyword" (
  "keyword" text,
  "kid" number PRIMARY KEY
);

CREATE TABLE "domain_keyword" (
  "did" number PRIMARY KEY,
  "kid" number,
  FOREIGN KEY ("did") REFERENCES "domain"("did"),
  FOREIGN KEY ("kid") REFERENCES "keyword"("kid")
);

CREATE TABLE "publication" (
  "abstract" text,
  "cid" text,
  "citation_num" number,
  "jid" number,
  "pid" number PRIMARY KEY,
  "reference_num" number,
  "title" text,
  "year" number,
  FOREIGN KEY ("cid") REFERENCES "conference"("cid"),
  FOREIGN KEY ("jid") REFERENCES "journal"("jid")
);

CREATE TABLE "domain_publication" (
  "did" number PRIMARY KEY,
  "pid" number,
  FOREIGN KEY ("did") REFERENCES "domain"("did"),
  FOREIGN KEY ("pid") REFERENCES "publication"("pid")
);

CREATE TABLE "organization" (
  "continent" text,
  "homepage" text,
  "name" text,
  "oid" number PRIMARY KEY
);

CREATE TABLE "publication_keyword" (
  "pid" number,
  "kid" number PRIMARY KEY,
  FOREIGN KEY ("kid") REFERENCES "keyword"("kid"),
  FOREIGN KEY ("pid") REFERENCES "publication"("pid")
);

CREATE TABLE "writes" (
  "aid" number PRIMARY KEY,
  "pid" number,
  FOREIGN KEY ("aid") REFERENCES "author"("aid"),
  FOREIGN KEY ("pid") REFERENCES "publication"("pid")
);

CREATE TABLE "cite" (
  "cited" number,
  "citing" number,
  FOREIGN KEY ("citing") REFERENCES "publication"("pid"),
  FOREIGN KEY ("cited") REFERENCES "publication"("pid")
);

